mapper.select:
SELECT c.code_id, c.code_group_id, g.group_code, c.code_value, c.code_name, c.sort_order, c.is_active
FROM TB_HKTMS_CODE c
JOIN TB_HKTMS_CODE_GROUP g ON g.code_group_id = c.code_group_id
WHERE g.group_code = #{groupCode}
  AND c.code_value = #{codeValue}
  AND c.deleted_at IS NULL

SELECT c.code_id, c.code_group_id, g.group_code, c.code_value, c.code_name, c.sort_order, c.is_active FROM TB_HKTMS_CODE c JOIN TB_HKTMS_CODE_GROUP g ON g.code_group_id = c.code_group_id WHERE g.business_unit = #{businessUnit} AND g.category_level = #{categoryLevel}
AND g.parent_code_value = #{parentCodeValue}
AND c.is_active = TRUE AND g.is_active = TRUE AND c.deleted_at IS NULL AND g.deleted_at IS NULL ORDER BY c.sort_order, c.code_id
